#include <cstdio>
using namespace std;
int n,l;
int f[25];
bool vis[25];
void dfs(int nk,int sg) {
	if(nk>l){
		for(int i=1;i<=l;++i)printf("%d ",f[i]);
		puts("");return;
	}
	for(int i=sg+1;i<=n;++i) {
		if(!vis[i]){
			f[nk]=i;vis[i]=1;
			dfs(nk+1,i);
			f[nk]=0;vis[i]=0;
		}
	}
}
int main(void){
	scanf("%d%d",&n,&l);
	dfs(1,0);
	return false;
}
